import { apiClient, unwrap, type BffResponse } from './api';
import type { CatalogUiSchema, SaveCatalogUiSchema } from '../types/catalogUiSchema';

const base = (catalogKind: string) => `/master/catalogs/${encodeURIComponent(catalogKind)}/ui-schema`;

export const catalogUiSchemaService = {
  get: async (catalogKind: string, configMode = false): Promise<CatalogUiSchema> => {
    const qs = configMode ? '?configMode=true' : '';
    const res = await apiClient.get<BffResponse<CatalogUiSchema>>(`${base(catalogKind)}${qs}`);
    return unwrap(res)!;
  },

  save: async (catalogKind: string, body: SaveCatalogUiSchema): Promise<CatalogUiSchema> => {
    const res = await apiClient.put<BffResponse<CatalogUiSchema>>(base(catalogKind), body);
    return unwrap(res)!;
  },
};
